51	// InitOptions contains all configuration options for project initialization
52	type InitOptions struct {
53		Force               bool   // Force initialization even if config exists
54		NoGit               bool   // Skip git-related operations
55		Silent              bool   // Suppress all output except errors
56		SkipClaudeInjection bool   // Skip injecting meta-prompts into CLAUDE.md
57		Repository          string // Custom repository URL (overrides default)
58		Branch              string // Custom repository branch (overrides default)
59		DDxVersion          string // Binary version to stamp into versions.yaml
60	}
