361	// writeGlobalConfig writes the global DDx config file with convention defaults.
362	func writeGlobalConfig(path string) error {
363		if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
364			return fmt.Errorf("creating global config dir: %w", err)
365		}
366		content := "# DDx global machine configuration — written by ddx init --global\nversion: \"1.0\"\n"
367		return os.WriteFile(path, []byte(content), 0644)
368	}
