384		// (FEAT-015). In the project-local model the DDx-managed ddx skill is a
385		// real directory. A symlink indicates a pre-migration DDx install;
386		// project-owned non-DDx skill symlinks are allowed.
387		if legacyDirs := legacySkillSymlinkDirs(f.WorkingDir); len(legacyDirs) > 0 {
388			errOut := cmd.ErrOrStderr()
389			for _, dir := range legacyDirs {
390				fmt.Fprintf(errOut, "DDx skill symlink detected under %s; pre-migration DDx skill install detected\n", dir)
391			}
392			fmt.Fprintln(errOut, "run: ddx update --force")
393			return fmt.Errorf("legacy DDx skill symlinks detected")
394		}
395	
396		fmt.Println()
397		if allGood && len(issues) == 0 {
398			fmt.Println("🎉 All critical checks passed! DDX is ready to use.")
399		} else if allGood && len(issues) > 0 {
400			fmt.Println("⚠️  Some non-critical issues detected. DDX is functional but may have limitations.")
401			fmt.Println("💡 Run 'ddx doctor --help' for troubleshooting tips.")
402		} else {
403			fmt.Println("⚠️  Some issues detected. DDX may have limited functionality.")
404			fmt.Println("💡 Run 'ddx doctor --help' for troubleshooting tips.")
405		}
406	
407		// Generate detailed diagnostic report if verbose or issues detected
408		if verbose || len(issues) > 0 {
409			generateDiagnosticReport(issues, verbose, f.WorkingDir)
410		}
411	
412		return nil
413	}
