522	// checkBinaryInstallLocation verifies the running binary is at the canonical install
523	// location ($HOME/.local/bin/ddx) and scans PATH for other ddx copies whose
524	// SHA-256 differs from the running binary.
525	func checkBinaryInstallLocation(executable string) []DiagnosticIssue {
526		var issues []DiagnosticIssue
527	
528		homeDir, err := os.UserHomeDir()
529		if err != nil {
530			return issues
531		}
532	
533		canonicalPath := filepath.Join(homeDir, ".local", "bin", "ddx")
534	
535		// (2) Check whether running binary matches the canonical install location.
536		resolvedExec, _ := filepath.EvalSymlinks(executable)
537		if resolvedExec == "" {
538			resolvedExec = executable
539		}
540		resolvedCanonical, _ := filepath.EvalSymlinks(canonicalPath)
541		execMatchesCanonical := resolvedExec == canonicalPath ||
542			(resolvedCanonical != "" && resolvedExec == resolvedCanonical)
543		if !execMatchesCanonical {
544			issues = append(issues, DiagnosticIssue{
545				Type:        "binary_not_canonical",
546				Description: fmt.Sprintf("Running binary (%s) is not at canonical install location (%s)", executable, canonicalPath),
547				Remediation: []string{
548					"Re-run install.sh to reinstall to the canonical location",
549					fmt.Sprintf("Or ensure %s is earlier in your PATH", filepath.Dir(canonicalPath)),
550				},
551			})
552		}
553	
554		// (3) Walk PATH and flag any ddx copy whose SHA-256 differs from the running binary.
555		runningSHA, err := computeFileSHA256(executable)
556		if err != nil {
557			return issues
558		}
559	
560		seen := make(map[string]bool)
561		for _, dir := range filepath.SplitList(os.Getenv("PATH")) {
562			candidate := filepath.Join(dir, "ddx")
563			if seen[candidate] {
564				continue
565			}
566			seen[candidate] = true
567	
568			info, err := os.Stat(candidate)
569			if err != nil || !info.Mode().IsRegular() || info.Mode()&0111 == 0 {
570				continue
571			}
572	
573			candidateSHA, err := computeFileSHA256(candidate)
574			if err != nil {
575				continue
576			}
577	
578			if candidateSHA == runningSHA {
579				continue // same binary, not stale
580			}
581	
582			issues = append(issues, DiagnosticIssue{
583				Type:        "binary_sha_mismatch",
584				Description: fmt.Sprintf("Stale ddx copy on PATH: %s (SHA-256 differs from running binary)", candidate),
585				Remediation: []string{
586					fmt.Sprintf("rm %s && cp %s %s", candidate, executable, candidate),
587					"Or re-run install.sh to update all copies",
588				},
589			})
590		}
591	
592		return issues
593	}
594	
595	// computeFileSHA256 returns the hex-encoded SHA-256 digest of the named file.
596	func computeFileSHA256(path string) (string, error) {
597		f, err := os.Open(path)
598		if err != nil {
599			return "", err
600		}
601		defer f.Close()
602	
603		h := sha256.New()
604		if _, err := io.Copy(h, f); err != nil {
605			return "", err
606		}
607		return hex.EncodeToString(h.Sum(nil)), nil
608	}
