957	func looksLikePluginInstall(entry registry.InstalledEntry) bool {
958		candidates := make([]string, 0, 2+len(entry.Files))
959		if root := installedEntryRootCandidate(entry); root != "" {
960			candidates = append(candidates, root)
961		}
962		candidates = append(candidates, entry.Files...)
963	
964		for _, candidate := range candidates {
965			path := registry.ExpandHome(strings.TrimSpace(candidate))
966			if path == "" {
967				continue
968			}
969	
970			info, err := os.Lstat(path)
971			if err != nil {
972				continue
973			}
974	
975			if info.IsDir() || info.Mode()&os.ModeSymlink != 0 {
976				return true
977			}
978		}
979	
980		return false
981	}
